document.addEventListener("DOMContentLoaded",()=>{const defaultStepHandler=(target,name,step)=>{const codeElements=target.parentElement.querySelectorAll("code");const codeValues=[];for(const code of codeElements){codeValues.push(code.innerText);}
const param=encodeURIComponent(codeValues.join(","));target.href=`${target.href}?${name}=${param}`;};const anchors=document.querySelectorAll(".md-content__inner a");for(const a of anchors){const match=a.href.match(/inst\/step-(\d)\/$/i);if(!match){continue;}
const step=parseInt(match[1]);defaultStepHandler(a,"param",step);}});document.addEventListener("DOMContentLoaded",()=>{const match=location.pathname.match(/inst\/step-(\d)\/$/i);if(!match||location.search.length===0){return;}
const step=parseInt(match[1]);const releaseBase="https://github.com/fioritracker";const placeholder={"1":"Release","2":"ICF node","3":"service name","4":"Role",};const singularForStep={"1":"release","2":"node","3":"service","4":"role",}
const searchParams=new URLSearchParams(location.search);if(!searchParams.has("param")){return;}
const param=searchParams.get("param").split(",");const newNodes=[];for(let i=0;i<param.length;i++){const p=param[i];const codeElement=document.createElement("code");codeElement.innerHTML=p;newNodes.push(codeElement);if(i!==param.length-1){newNodes.push(document.createTextNode(", "));}}
if(param.length===1){newNodes.push(document.createTextNode(` ${singularForStep[step]}`));}else{newNodes.push(document.createTextNode(` ${singularForStep[step]}s`));}
const internalCodeElements=document.querySelectorAll(".md-content__inner code");for(const el of internalCodeElements){if(el.innerHTML===placeholder[step]){el.replaceWith(...newNodes.map(n=>n.cloneNode(true)));}else if(el.innerHTML.includes(placeholder[step])&&param.length===1){const codeCopy=el.cloneNode(true);codeCopy.innerHTML=codeCopy.innerHTML.replace(placeholder[step],param[0]);newNodes[0]=codeCopy;newNodes.splice(newNodes.length-1);el.replaceWith(...newNodes.map(n=>n.cloneNode(true)));}}});